import Vue from 'vue'
import Vuex from 'vuex'
import * as types from './mutation-types'
import {userUrl} from '../constants'

Vue.use(Vuex)

export default new Vuex.Store({
  state: {
    data: null,
    error: null
  },
  mutations: {
    [types.GET_USER](state, payload) {
      console.log(payload)
      state.data = payload
      state.error = null;
    },
    [types.CLEAR_ALL](state) {
      state.data = null;
      state.error = null;
    }
  },
  actions: {
    getUser({commit}, payload) {
      commit(types.CLEAR_ALL);
      fetch(`${userUrl}/users/${payload}`)
        .then(res => {
        return res.json()
          .then(result => {
          if(
      !result.login
    )
      {
        result.login = payload;
      }
      commit(types.GET_USER, result);
      return true;
    })
    })
    .
      catch((err) => {
        commit(types.GET_USER, err
    )
      ;
    })
    }
  }
})
