import Vue from 'vue'
import Router from 'vue-router'
import Home from './views/Home.vue'
import User from './views/User.vue'
import NotFound from './views/NotFound.vue'
import Repo from './views/Repo'

Vue.use(Router)

export default new Router({
  mode: 'history',
  routes: [
    {
      path: '/',
      name: 'home',
      component: Home
    },
    {
      path: '/:name',
      name: 'user',
      component: User
    },
    {
      path: '/:name/:repo',
      name: 'repo',
      component: Repo
    },
    {
      path: '/404',
      name: 'not-found',
      component: NotFound
    },
    {
      path: '*',
      redirect: '/404'
    }
  ]
})
