<template>
    <div class="repo">
        <div class="repo-breadcrumbs">
            <icon name="book"/>
            <router-link :to="'/' + $route.params.name">{{$route.params.name}}</router-link>
            <span> / </span>
            <router-link :to="'/' + $route.params.name + '/' + $route.params.repo">{{$route.params.repo}}</router-link>
        </div>
        <div class="centred" v-if="spinner">
            <icon name="spinner" spin scale="2"></icon>
        </div>
        <h1 class="centred" v-if="error">
            {{error}}
        </h1>
        <div v-if="!error && data">
            <div class="row" v-for="item in data" :key="item.label" v-if="item.value">
                <div class="col">
                    {{item.label}}
                </div>
                <div class="col">
                    <span v-html="item.value"></span>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
  import {userUrl} from '../constants'
  import Icon from 'vue-awesome/components/Icon'
  import * as CONSTANTS from '../constants'

  const ALLOW_RESULTS = [
                'name',
                'homepage',
                'description',
                'created_at',
                'updated_at',
                'forks',
                'language',
                'license',
                'open_issues',
                'size',
                'stargazers_count',
                'subscribers_count',
                'watchers'
  ]

  export default {
    data() {
      return {
        data: null,
        spinner: true,
        error: null
      }
    },
    created: function () {
      fetch(`${userUrl}/repos/${this.$route.params.name}/${this.$route.params.repo}`)
        .then(res => res.json()
          .then(result => {
            this.spinner = false
            if (result.message) {
              this.error = result.message;
            } else {
              this.data = ALLOW_RESULTS.map(item => {
                return {value: CONSTANTS.TYPE_CHECKER(result[item]), label: item.replace('_', ' ').replace(/\b\w/g, l => l.toUpperCase())}
              })  
            }
          })
        )
        .catch(err => {
          this.spinner = false
          if (err && err.message) {
            this.error = err.message
          }
        })
    },
    components: {
      Icon
    },
  }
</script>

<style scoped lang="less">
    @import "../assets/less/style";

    .repo {
        width: 100%;
        margin: 10px;
    }

    .repo-breadcrumbs {
        display: flex;
        align-items: center;
        width: 100%;
        margin: 10px 0 10px 0;
    }

    .fa-icon {
        color: #aaa;
    }

    .row {
        display: inline-flex;
        width: 100%;
        border-bottom: 1px solid #ccc;
        padding: 10px;
    }

    .col {
        display: flex;
        width: 45%;
    }
</style>
