<template>
    <div>
        <div class="row" v-for="item in getItems" :key="item.label" v-if="item.value">
            <div class="col">
                {{item.label}}
            </div>
            <div class="col">
                <div v-if="urlChecker(item.value)">
                    <a :href="item.value">{{item.value}}</a>
                </div>
                <div v-else>{{item.value}}</div>
            </div>
        </div>
    </div>
</template>

<script>
  import {URL_REGEXP, TYPE_CHECKER} from '../constants'

  const ALLOW_RESULTS = [
          'name',
          'email',
          'company',
          'blog',
          'bio',
          'created_at',
          'updated_at',
          'followers',
          'following',
          'hireable',
          'location',
          'public_repos'
  ]

  export default {
    props: ['user'],
    methods: {
      urlChecker: function (value) {
        if (!value) return false
        return URL_REGEXP.test(value)
      }
    },
    computed: {
      getItems() {
          return ALLOW_RESULTS.map(item => {
            return {value: TYPE_CHECKER(this.user[item]), label: item.replace('_', ' ').replace(/\b\w/g, l => l.toUpperCase())}
          }) 
      }
    }
  }
</script>

<style scoped lang="less">
    .row {
        display: inline-flex;
        width: 100%;
        flex-wrap: wrap;
        border-bottom: 1px solid lightgrey;
    }

    .col {
        display: flex;
        width: 45%;
        padding: 5px;
    }
</style>

